var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"으음...... 졸려.","JPN":"ううん……眠い。","ENG":"Mm... Sleepy...","TWN":"嗯……好睏。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"회장~ 나 그냥 자러 가면 안돼?","JPN":"会長～、私だけ寝ちゃダメ～？","ENG":"Yeeen, can't I just go sleeeep?","TWN":"會長～我能不能去睡覺啊！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"물에서 혼자 헤엄쳐나올 수 있을 때까진 안돼요.","JPN":"一人で泳げるようになるまではダメです。","ENG":"No, not until you can swim out of the water on your own.","TWN":"直到妳能在水中自己游出來為止，否則都不準。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"히잉, 너무해. 나한테 수영을 시키다니~","JPN":"はうぅ、ひどい。私に水泳をさせるなんて～。","ENG":"Hng, you're such a meanine! I can't believe you're forcing me to swim!","TWN":"嗚，好過分。竟然讓我游泳～"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"여행준비를 한다고 해서 쇼핑센터에라도 가는 줄 알았는데에~","JPN":"旅行準備をするって言ってたから、ショッピングセンターにでも行くかと思ったんだけどなぁ～。","ENG":"When you said we were getting ready to travel, I thought we were going to a shopping center.","TWN":"說要準備去旅行，我還以為是去購物中心呢～"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"미안해요, 이디스.","JPN":"ごめんなさい、イーディス。","ENG":"I'm sorry, Edith.","TWN":"抱歉，伊蒂絲。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"하지만 당신이 지난 번처럼 수영장 물을 잔뜩 마시고 응급실에 실려가는 일은 겪지 않았으면 좋겠어요.","JPN":"しかし、あなたがこの前みたいにプールで水をいっぱい飲んで、救急室に運ばれるような経験を二度としてほしくないのです。","ENG":"But I don't want you to drown and be rushed to the emergency room ever again.","TWN":"但我不希望妳又像上次那樣，因為喝了太多泳池裡的水，所以被送到急診室。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"우리 회장은 걱정이 너무 많다니까.","JPN":"うちの会長は心配性なんだから。","ENG":"Yen, you worry too much.","TWN":"我們會長就是愛操心。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"하암~ 어쩔 수 없지.","JPN":"ふわぁ～仕方ないなぁ。","ENG":"*Yawn* But okay.","TWN":"哈啊～沒辦法了。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"그럼 내가 레인 끝에서 끝까지 완주하면 보내주는 거야?","JPN":"じゃあ、私がプールの端から端まで泳ぎ切ったら帰してくれるのぉ？","ENG":"Then, will you let me go if I reach the other end of a swimming lane?","TWN":"那我在泳池裡游一個來回，這樣就可以了吧？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"물론이죠. 그 정도 실력만 되더라도 이디스를 붙잡아두지 않을게요.","JPN":"もちろんです。それぐらいの実力さえあれば、イーディスを引き止めたりしません。","ENG":"Of course. I'll let you go if you can do that, Edith.","TWN":"當然，如果伊蒂絲有這種實力，我就不會再強迫妳了。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"야호~ 그러면......","JPN":"やった～、じゃあ……","ENG":"Wee! Then...","TWN":"呀呼～那就……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"대신 로봇을 쓰는 건 안돼요.","JPN":"その代わり、ロボットを使っちゃだめですよ。","ENG":"Using your robot doesn't count.","TWN":"但不能使用機器人。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"왜애~","JPN":"なんでよ～。","ENG":"Why not?!","TWN":"為什麼～"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"돌발상황은 자기 힘으로 헤쳐나올 수 있어야죠.","JPN":"突発的な状況だと、自力で抜け出さないといけません。","ENG":"You have to be able to swim on your own in an emergency.","TWN":"遇到突發狀況時，必須要用自己的力量克服才行。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"늘 기계의 도움만 받으려고 해선 곤란하다고 누누이 얘기했었잖아요?","JPN":"機械に頼ってばかりじゃ困るって何度も言いましたよね？","ENG":"How many times do I have to tell you that you can't always rely on machines?","TWN":"老是依賴機器是會出問題的，這我不是說過好多次了嗎？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"으으...... 알았어.","JPN":"あうぅ……わかった。","ENG":"Gah! Fine!","TWN":"唔唔……知道了。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"이런 풋내기 꼬마들이 들끓는 곳에서 사랑을 찾으라니, 운명의 시련은 참 가혹하군요.","JPN":"まだ青い学生ばかりいるところで恋を探すなんて、運命の試練って過酷ですね。","ENG":"My destiny is so harsh, forcing me to look for the love of my life among these little kids.","TWN":"竟然要在這麼多小鬼的地方尋找真愛，命運的試煉還真夠殘酷的。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"아하하...... 그야 모르는 일이죠. 수영강사와 눈이 맞을지도 모르잖아요?","JPN":"あはは……まだわかりませんよ。水泳の教師と通じ合うかもしれませんしね。","ENG":"Ah hah hah. But who knows; he might be their swimming instructor.","TWN":"啊哈哈……這說不準吧，也許會跟游泳教練對上眼也說不定呢？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"로자리아 님은 결국 오지 않으셨네요.","JPN":"ロザリアさんは結局来なかったんですね。","ENG":"Lady Rosaria really didn't come.","TWN":"羅莎莉亞大人最終還是沒來。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"그러게요. 오랜만에 걸어 다니느라 다리가 아프다고 하셨었죠?","JPN":"そうですね。久々に歩き回って足が疲れたとか言ってましたよね？","ENG":"I know. She said her legs were hurting from walking for the first time in a long time.","TWN":"是啊，她說太久沒走路，腿很痛。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"쉬겠다는 사람 붙잡고 데려오는 것도 예의가 아니니까 그 동안 우리끼리 재미있게 놀자고요.","JPN":"疲れてる人を連れてくるのも悪いですし、私たちで楽しみましょう。","ENG":"We can't force her if she doesn't want to come. Let's have fun without her.","TWN":"硬是把想要休息的人帶過來可不是什麼禮貌行為，那我們就幾個人好好玩吧。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"그 사람...... 아무래도 자기가 의뢰를 맡고 있다는 자각이 없는 것 같아.","JPN":"あの人……どうやら依頼を引き受けている自覚がなさそう……","ENG":"I don't think she knows she's here to work, or even cares about that.","TWN":"那個人……看來沒有自己已經接受委託的自覺呢。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"흐음~ 운명의 상대를 찾는다는 게 얼마나 대단한 일인지 저는 잘 모르겠네요.","JPN":"ふう～ん、運命の相手を探すことがどれだけ大事なことなのか私にはわかりません。","ENG":"Hm, I don't know how important it is to find your soul mate.","TWN":"嗯～尋找命運之人到底有什麼難的，我還真是不明白呢。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"그냥 저기 있는 남자 선생님들 중에 한 명과 만나보는 것도 괜찮지 않겠어요?","JPN":"ただ、あそこにいる男性の先生の中の一人と会ってみるのもいいんじゃないですか？","ENG":"Can't you just meet one of those male teachers over there?","TWN":"就在那幾個男老師當中選一個怎麼樣？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"그게 쉬웠으면 제 팔자가 이렇게 꼬였겠습니까?","JPN":"そんなに簡単にできることだったら、私の人生はここまでめちゃくちゃになってませんよ。","ENG":"If that was so easy, I wouldn't be here now, would I?","TWN":"如果事情那麼簡單，我的命運不至於會這麼坎坷吧。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"남자 앞에만 서면 혀가 꼬이고, 내가 웃기만 하면 다들 놀라서 도망가는데.","JPN":"男の人の前に立つと、どもってしまったり、私が笑うとみんな驚いて逃げてしまうのに……","ENG":"I can't talk to men. They run away when I smile.","TWN":"我只要站在男生面前舌頭就會打結，我只要一笑就會嚇跑所有人。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Sorry?","TWN":"什麼？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"아, 혼잣말이에요. 혼잣말.","JPN":"あ、独り言です。独り言。","ENG":"Oh, never mind. I was just talking to myself.","TWN":"啊，是我在自言自語而已，自言自語。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"......그나저나 여긴 학교수영장인 주제에 무슨 궁전처럼 넓네요.","JPN":"……ところで、ここって学校のプールなのに、なんか宮殿みたいに広いですね。","ENG":"By the way, this pool is as big as a palace.","TWN":"……話說回來，這裡明明只是學校的游泳池，卻大得像宮殿一樣。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"이 정도로 크게 지을 필요가 있나?","JPN":"これほど大きく建てる必要あるんですかね？","ENG":"Does a school need such a big pool?","TWN":"有必要建這麼大嗎？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"글쎄요. 로비직원에게 듣기론 이 수영장에 꽤 특이한 소문이 있대요.","JPN":"さあ。ロビーの職員の話によると、このプールにはかなり不思議な噂があるらしいですよ。","ENG":"Beats me. But the receptionist I talked to at the lobby told me a strange rumor about this pool.","TWN":"不知道耶，我聽大廳的接待員說，這個游泳池有一個神秘的傳聞。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"특이한 소문?","JPN":"……不思議な噂？","ENG":"What strange rumor?","TWN":"神秘的傳聞？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"방학 때마다 안에서 무슨 비밀병기 같은 걸 개발하고 있다나 뭐라나, 하하.","JPN":"学校の休みのたびに、中で何か秘密兵器みたいなものを開発してるとかなんとか、ハハ。","ENG":"It's a front for a secret weapon lab that's operated during every vacation. Hah hah.","TWN":"據說每到假期，就會有人在游泳池裡開發秘密武器之類的，哈哈。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"학교수영장 안에 비밀병기라니 무슨 그런 억지가 다 있죠?","JPN":"学校のプールで秘密兵器とは、無茶苦茶な噂ですね。","ENG":"A secret weapon lab under the school pool. That's ridiculous.","TWN":"在學校游泳池裡研發秘密武器，這不可能吧？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"그러게나 말이에요.","JPN":"ですよね。","ENG":"Tell me about it.","TWN":"可不是嗎。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"STUDENT_EXTRA_NULL_NULL","text":{"KOREA":"정말로 괜찮은 걸까? 저 언니, 엄청 허우적대는데......","JPN":"本当に大丈夫かな？　あのお姉さん、すごいジタバタしてるけど……","ENG":"Are you sure she's okay? She looks like she's drowning...","TWN":"真的沒事嗎？那個姐姐在水裡奮力掙扎呢……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"어라? 저쪽에 사람들이 모여있네요. 무슨 소란이지?","JPN":"あれ？　あっちに人だかりができてますよ。何の騒ぎだろう？","ENG":"Hmm? A crowd has gathered over there. What's going on?","TWN":"咦？那邊怎麼那麼多人，出什麼事了？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"어푸! 어푸우!","JPN":"あっぷ！　あっぷ！","ENG":"Poof! Pooffff!","TWN":"噗！啊噗！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"이런! 물에 빠진 사람이 있는 것 같아요, 빨리 구하러 가셔야죠?","JPN":"そんな！　溺れてる人がいるようです、早く助けに行ってください。","ENG":"Oh, no! Someone's drowning. You should go save her!","TWN":"天啊！有人溺水了，妳快去救人呀？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"네? 제가 왜......","JPN":"はい？　なんで私が……","ENG":"Huh? Me? Why me?","TWN":"咦？為什麼是我……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"그야 위험에 처한 사람을 도와주는 모습을 보여주면 누군가 호감을 느끼고 접근할 지도 모르잖아요?","JPN":"危険にさらされた人を助ける姿を見せれば、誰かが好感を抱いて近づいてくるかもしれませんよ？","ENG":"Because someone might feel attracted to you when he sees how heroic you are.","TWN":"只要妳展現勇於救人的樣子，說不定能獲得某個異性的好感啊？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"그야말로 절호의 기회에요!","JPN":"まさに絶好のチャンスです！","ENG":"This is your chance!","TWN":"這可是大好機會啊！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"그...... 별로 믿음이 가지 않는 주장인데요......","JPN":"それは……あまり信用できない主張ですが……","ENG":"I... doubt that.","TWN":"呃……這好像不是什麼值得信賴的主意……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"거기다가 저 여자애, 아무래도 물에 빠진 게 아닌 것 같은데......","JPN":"それにあの女の子、どうやら溺れてるんじゃないみたいですけど……","ENG":"Besides, I don't think she's drowning.","TWN":"而且那個女孩好像沒有溺水……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"어서요! 운명을 만나는 것도 적극적으로 나서야 할 수 있죠! 머뭇거리고 있을 틈이 없어요!","JPN":"早く！　運命の人に巡り合うためには積極的に挑まないとダメですよ！","ENG":"Come on! You can't meet the man of your dreams just by sitting here. Get your butt in gear already!","TWN":"快啊！要迎接命運也要妳積極地跨出那一步才行！沒有時間猶豫了！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"에잇!","JPN":"えいっ！","ENG":"Eek!","TWN":"嘿！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"어! 어! 어디로 미는 거야! 이 여자야!!","JPN":"えっ！　ええっ！？　押すな！　押すなって！！","ENG":"Err? Err? Woman, stop pushing me!","TWN":"喂！喂！別推我啦！你這個女人！！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"고맙다는 말씀은 안 하셔도 돼요~","JPN":"お礼は結構ですから～。","ENG":"You're welcome!","TWN":"不用謝我啦～"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};